--
-- Table structure for table `users`
--

CREATE TABLE `users` (
  `id` int(11) NOT NULL,
  `username` varchar(255) NOT NULL,
  `position` varchar(100) DEFAULT NULL,
  `email` varchar(255) NOT NULL,
  `employee_id` varchar(50) DEFAULT NULL,
  `phone_number` varchar(20) DEFAULT NULL,
  `designation` varchar(100) NOT NULL,
  `department` varchar(100) DEFAULT NULL,
  `password` varchar(255) NOT NULL,
  `backup_password` varchar(255) DEFAULT NULL,
  `role` varchar(50) NOT NULL,
  `manager_id` int(11) DEFAULT NULL,
  `unique_id` varchar(10) NOT NULL,
  `reporting_manager` varchar(100) DEFAULT NULL,
  `parent_id` int(11) DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  `deleted_at` timestamp NULL DEFAULT NULL,
  `status` enum('Active','Inactive') DEFAULT 'Active',
  `last_login` datetime DEFAULT NULL,
  `profile_image` varchar(255) DEFAULT NULL,
  `address` text DEFAULT NULL,
  `emergency_contact` longtext DEFAULT NULL,
  `joining_date` date DEFAULT NULL,
  `modified_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  `city` varchar(100) DEFAULT NULL,
  `state` varchar(100) DEFAULT NULL,
  `country` varchar(100) DEFAULT NULL,
  `postal_code` varchar(20) DEFAULT NULL,
  `emergency_contact_name` varchar(255) DEFAULT NULL,
  `emergency_contact_phone` varchar(20) DEFAULT NULL,
  `phone` varchar(20) DEFAULT NULL,
  `dob` date DEFAULT NULL,
  `profile_picture` varchar(255) DEFAULT NULL,
  `bio` text DEFAULT NULL,
  `gender` enum('male','female','other') DEFAULT NULL,
  `marital_status` varchar(50) DEFAULT NULL,
  `nationality` varchar(100) DEFAULT NULL,
  `languages` text DEFAULT NULL,
  `social_media` longtext DEFAULT NULL,
  `skills` longtext DEFAULT NULL,
  `interests` longtext DEFAULT NULL,
  `blood_group` varchar(10) DEFAULT NULL,
  `education` longtext DEFAULT NULL,
  `work_experience` longtext DEFAULT NULL,
  `bank_details` text DEFAULT NULL,
  `notification_preferences` longtext DEFAULT NULL,
  `shift_id` int(11) DEFAULT NULL,
  `documents` text DEFAULT NULL,
  `work_experiences` longtext DEFAULT NULL,
  `education_background` longtext DEFAULT NULL,
  `base_salary` decimal(10,2) DEFAULT 0.00,
  `allowances` longtext DEFAULT NULL,
  `deductions` longtext DEFAULT NULL,
  `overtime_rate` decimal(10,2) DEFAULT 0.00,
  `status_changed_date` datetime DEFAULT NULL COMMENT 'Records when user status was last changed',
  `password_change_required` tinyint(1) DEFAULT 1 COMMENT 'Flag to indicate if password change is required (1=yes, 0=no)',
  `last_password_change` datetime DEFAULT NULL COMMENT 'Timestamp of last password change',
  `must_change_password` tinyint(1) NOT NULL DEFAULT 0,
  `password_changed_at` datetime DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='Stores user information including manager relationships';

